112	    wire         tvalid;
113	    wire [127:0] tdata;
114	    wire [3:0]   tkeepdw;
115	    wire         tlast;
116	    wire         first;
117	       
118	    fifo_134_134_clk2 i_fifo_134_134_clk2 (
119	        .rst        ( rst               ),
