121	        .rd_clk     ( clk_sys           ),
122	        .din        ( { tlps_in.tuser[0], tlps_in.tlast, tlps_in.tkeepdw, tlps_in.tdata } ),
123	        .wr_en      ( tlps_in.tvalid    ),
